END $$;
COMMIT;

SELECT 'Unidade Flamboyant' AS item, COUNT(*) AS total FROM "Unit" WHERE code = 'FLAMBOYANT';
SELECT 'Profissionais Flamboyant' AS item, COUNT(*) AS total FROM "User" WHERE "unitId" = 'seed_unit_flamboyant';
SELECT 'Alunos Flamboyant' AS item, COUNT(*) AS total FROM "Child" WHERE "unitId" = 'seed_unit_flamboyant';
SELECT c.name AS turma, COUNT(e.id) AS matriculas FROM "Classroom" c LEFT JOIN "Enrollment" e ON e."classroomId" = c.id AND e.status = 'ATIVA' WHERE c."unitId" = 'seed_unit_flamboyant' GROUP BY c.name ORDER BY c.name;